function solve(nums: number[]): number {
    const n = nums.length;
    const sorted = [...nums].sort((a, b) => a - b);

    // For each possible k, check if we can sort the array using swaps with AND equal to k
    for (let k = n - 1; k >= 0; k--) {
        const visited = new Array(n).fill(false);
        let canSort = true;

        for (let i = 0; i < n; i++) {
            if (visited[i]) continue;
            const target = sorted[i];
            let j = i;
            while (j < n && nums[j] !== target) {
                if ((nums[i] & nums[j]) === k) {
                    // Swap i and j
                    [nums[i], nums[j]] = [nums[j], nums[i]];
                    visited[i] = true;
                    visited[j] = true;
                    break;
                }
                j++;
            }
            if (j === n) {
                canSort = false;
                break;
            }
        }

        if (canSort) {
            return k;
        }
    }

    return 0;
}

